import React from "react";
import { Box, Flex, Heading, Button, Link, Text } from "theme-ui";
import { Link as GatsbyLink } from "gatsby";
import { DEFAULT_CATEGORY_COUNT } from "../../config";
import { useDisclosure } from "react-use-disclosure";
import Search from "../Search";
import { Star, Clock, Activity } from "../Icons";

export default function WithSubnavigation({ items, searchItems, location }) {
  return (
    <Box
      p="default"
      sx={{
        bg: "background",
        display: ["none", "block"],
        width: "320px",
        flexBasis: "320px",
        flexShrink: 0,
        position: "sticky",
        top: "82px",
        height: "calc(100vh - 82px)",
        overflowY: "auto",
        overscrollBehavior: "contain",
      }}
    >
      <Box>
        <MobileNav
          location={location}
          searchItems={searchItems}
          items={items}
        />
      </Box>
    </Box>
  );
}

export const MobileNav = ({ searchItems, items, location }) => {
  return (
    <Box sx={{ width: "full" }}>
      <Search location={location} items={searchItems}></Search>
      {items.map((navItem) => (
        <MobileNavItem key={navItem.label} {...navItem} />
      ))}
    </Box>
  );
};
const NavItemChildren = ({ items, showAll }) => {
  const { isOpen, toggle } = useDisclosure();
  return (
    <Flex sx={{ flexDirection: "column", alignItems: "flex-start" }}>
      {items &&
        items
          .filter((_, index) => {
            if (!showAll && !isOpen && index >= DEFAULT_CATEGORY_COUNT) {
              return false;
            } else {
              return true;
            }
          })

          .map((child, index) => (
            <Link
              as={GatsbyLink}
              color="textLight"
              key={
                Array.isArray(child.label)
                  ? child.label[0] + index
                  : child.label + index
              }
              to={child.href}
              variant="toc"
              sx={{
                my: "2px",
              }}
            >
              <Text
                sx={{
                  fontWeight: child.active ? 500 : 400,
                  mr: "2px",
                  color: child.active ? "blackTer" : "textLight",
                }}
              >
                {child.label[0]}
              </Text>
              <Text
                sx={{
                  fontSize: 1,
                  color: child.active ? "blackTer" : "textMuted",
                  svg: {
                    fill: child.active ? "blackTer" : "textMuted",
                  },
                }}
              >
                (<Activity></Activity>
                {child.label[2]}
                <Text mx="2px"></Text>
                <Star size={13}></Star>
                {child.label[1]})
              </Text>
            </Link>
          ))}
      {!showAll && items.length > DEFAULT_CATEGORY_COUNT && (
        <Button color="textLight" onClick={toggle} variant="link">
          {isOpen ? "- Show Less" : "+ Show More"}
        </Button>
      )}
    </Flex>
  );
};

const MobileNavItem = ({ label, children, href, showAll }) => {
  return (
    <Box pb="default">
      <Heading as="h3" pb="1">
        {label}
      </Heading>
      <NavItemChildren items={children} showAll={showAll}></NavItemChildren>
    </Box>
  );
};
