import React, { useEffect } from "react";
import { useStaticQuery, graphql } from "gatsby";
import Navbar from "../Navbar";
import Sidebar from "../Sidebar";
import { Box, Flex, Link } from "theme-ui";
import { Global } from "@emotion/react";
import "tippy.js/dist/tippy.css"; // optional for styling

import {
  isReadme as isReadmeFn,
  getPageType,
  getTitleByRepo,
} from "../../utils";
import Footer from "../Footer";
import { addBackToTop } from "vanilla-back-to-top";
import { OverlayProvider } from "@react-aria/overlays";
const Layout = ({ location, children, repo }) => {
  const pageType = getPageType(location.pathname);

  useEffect(() => {
    addBackToTop();
  }, []);
  const data = useStaticQuery(graphql`
    query {
      site {
        siteMetadata {
          title
        }
      }
      allAwesomeList {
        group(field: category) {
          field
          fieldValue
          nodes {
            slug
            repo
            categoryIndex
            stargazerCount
            readmeItemsUpdatedTime
          }
        }
      }
      searchAwesomeList: allAwesomeList(
        sort: { fields: readmeItemsUpdatedTime, order: DESC }
      ) {
        nodes {
          id
          slug
          name
          repo
          category
          description
          categoryIndex
          stargazerCount
          readmeItemsUpdatedTime
        }
      }
      topAwesomeList: allAwesomeList(
        sort: { fields: stargazerCount, order: DESC }
        limit: 50
      ) {
        nodes {
          slug
          repo
          stargazerCount
          readmeItemsUpdatedTime
        }
      }
      recentAwesomeList: allAwesomeList(
        sort: { fields: readmeItemsUpdatedTime, order: DESC }
        limit: 50
      ) {
        nodes {
          slug
          repo
          stargazerCount
          readmeItemsUpdatedTime
        }
      }
    }
  `);
  const navItems = data.allAwesomeList.group
    .sort((a, b) => {
      return a.nodes[0].categoryIndex - b.nodes[0].categoryIndex;
    })
    .map((category) => {
      return {
        label: category.fieldValue,
        children: category.nodes
          .sort((a, b) => {
            return b.stargazerCount - a.stargazerCount;
          })
          .filter((item) => {
            return (
              item.readmeItemsUpdatedTime >
              new Date(process.env.GATSBY_UNMAINTAINED_TIME)
            );
          })
          .map((item) => {
            return {
              label: getTitleByRepo(
                item.repo,
                item.stargazerCount,
                new Date(item.readmeItemsUpdatedTime)
              ),
              active: item.repo === repo,
              href:
                pageType === "week" || pageType === "homeWeek"
                  ? item.slug + "/week"
                  : pageType === "readme"
                  ? item.slug + "/readme"
                  : item.slug,
            };
          }),
      };
    });

  navItems.unshift({
    label: "Recently Updated",
    children: data.recentAwesomeList.nodes.map((item, index) => {
      return {
        label: getTitleByRepo(
          item.repo,
          item.stargazerCount,
          new Date(item.readmeItemsUpdatedTime)
        ),
        active: item.repo === repo,

        href:
          pageType === "week"
            ? item.slug + "/week"
            : pageType === "readme"
            ? item.slug + "/readme"
            : item.slug,
      };
    }),
  });
  // add top awesome list
  navItems.unshift({
    label: "Top 50 Awesome List",
    children: data.topAwesomeList.nodes
      .filter((item) => {
        return (
          item.readmeItemsUpdatedTime >
          new Date(process.env.GATSBY_UNMAINTAINED_TIME)
        );
      })
      .map((item, index) => {
        return {
          label: getTitleByRepo(
            item.repo,
            item.stargazerCount,
            new Date(item.readmeItemsUpdatedTime),
            index
          ),
          active: item.repo === repo,

          href:
            pageType === "week"
              ? item.slug + "/week"
              : pageType === "readme"
              ? item.slug + "/readme"
              : item.slug,
        };
      }),
  });
  const unmaintainedList = data.searchAwesomeList.nodes
    .filter((item) => {
      return (
        item.readmeItemsUpdatedTime <
        new Date(process.env.GATSBY_UNMAINTAINED_TIME)
      );
    })
    .slice(0, 50)
    .map((item, index) => {
      return {
        label: getTitleByRepo(
          item.repo,
          item.stargazerCount,
          new Date(item.readmeItemsUpdatedTime)
        ),
        active: item.repo === repo,

        href:
          pageType === "week"
            ? item.slug + "/week"
            : pageType === "readme"
            ? item.slug + "/readme"
            : item.slug,
      };
    });
  if (unmaintainedList.length) {
    navItems.push({
      label: "Unmaintained",
      children: unmaintainedList,
    });
  }

  const title = data.site.siteMetadata.title;

  return (
    <OverlayProvider>
      <Global
        styles={(theme) => ({
          "& :target::before": {
            content: "''",
            display: "block",
            height: "75px",
            marginTop: "-75px",
          },
        })}
      ></Global>
      <Box>
        <Navbar
          title={title}
          location={location}
          searchItems={data.searchAwesomeList.nodes}
          items={navItems}
        ></Navbar>
        <Box>
          <Flex>
            <Sidebar
              location={location}
              searchItems={data.searchAwesomeList.nodes}
              items={navItems}
            ></Sidebar>
            <Box sx={{ flex: 1, pl: [0, "md"] }} as="main">
              {children}
            </Box>
          </Flex>
          <Footer></Footer>
        </Box>
      </Box>
    </OverlayProvider>
  );
};

export default Layout;
