export const groupByTimeWithRepo = (nodes, type) => {
  const dateGrouped = nodes.reduce(
    (
      r,
      v,
      i,
      a,
      k = type === "week" || type === "homeWeek"
        ? getWeekISOByISO(v.updatedAt)
        : getDayISOByISO(v.updatedAt)
    ) => ((r[k] || (r[k] = [])).push(v), r),
    {}
  );
  const rootGroups = [];
  Object.keys(dateGrouped).map((groupKey, rootIndex) => {
    const groupItems = dateGrouped[groupKey];
    const grouped = groupItems.reduce(
      (r, v, i, a, k = v.awesomeListRepo) => ((r[k] || (r[k] = [])).push(v), r),
      {}
    );
    // 排序
    const groups = Object.keys(grouped).map((groupKey) => {
      const groupItems = grouped[groupKey];

      // groupd by Category
      const groupedByCategory = groupItems.reduce(
        (r, v, i, a, k = v.categoryHTML) => ((r[k] || (r[k] = [])).push(v), r),
        {}
      );
      let itemsHtml = "";
      Object.keys(groupedByCategory)
        .slice(0, 3)
        .forEach((categoryGroupKey) => {
          itemsHtml += `${categoryGroupKey}\n`;
          const items = groupedByCategory[categoryGroupKey];
          items.slice(0, 5).forEach((item) => {
            itemsHtml += item.itemHTML + "\n";
          });
        });
      return {
        awesomeListRepo: groupKey,
        itemsHTML: itemsHtml,
      };
    });
    const updateDateObj = new Date(groupKey);

    const [updateYear, updateWeek] = getWeekNumber(updateDateObj);
    const updateWeekId = updateYear + "-" + updateWeek;

    const dayId = getDayByISO(groupKey);
    const daySlug = getSlugByDay(dayId);
    rootGroups[rootIndex] = {
      id: type === "week" || type === "homeWeek" ? updateWeekId : dayId,
      slug:
        type === "week" || type === "homeWeek"
          ? `/${updateYear}/${updateWeek}/`
          : daySlug,
      updatedAt: groupKey,
      updateDate: dayId,
      updateWeek: updateWeekId,
      updateTime: updateDateObj.getTime(),
      groups,
    };
  });

  return rootGroups;
};

export const getWeekISOByISO = (isoString) => {
  const date = new Date(isoString);

  let currentDay = date.getUTCDay();
  if (currentDay === 0) {
    currentDay = 7;
  }
  const distance = 1 - currentDay;
  date.setUTCDate(date.getUTCDate() + distance);
  date.setUTCHours(0);
  date.setUTCMinutes(0);
  date.setUTCSeconds(0);
  date.setUTCMilliseconds(0);
  return date.toISOString();
};
export const getDayISOByISO = (isoString) => {
  return new Date(getDayByISO(isoString)).toISOString();
};
export const getDayByISO = (isoString) => {
  const dateArr = isoString.split("T");
  return dateArr[0];
};
export const getWeekByISO = (isoString) => {
  const date = new Date(isoString);
  return `${date.getWeekNumber(date).join("-")}`;
};
export const sortByUpdatedAt = (arr) => {
  return arr.sort((a, b) => {
    return new Date(b.updatedAt) - new Date(a.updatedAt);
  });
};
export const getISOStringByDay = (someDate) => {
  const d = new Date(someDate);
  return d.toISOString();
};
export const isReadme = (pathname) => {
  const currentPathnameArr = pathname.split("/");
  const isReadme =
    currentPathnameArr[currentPathnameArr.length - 1] === "readme" ||
    currentPathnameArr[currentPathnameArr.length - 2] === "readme";
  return isReadme;
};
function isNumeric(number) {
  return !isNaN(parseFloat(number)) && !isNaN(+number);
}

export const getPageType = (pathname) => {
  const currentPathnameArr = pathname.split("/").filter((item) => item);

  const lastSlug = currentPathnameArr[currentPathnameArr.length - 1];
  const lastSlug2 = currentPathnameArr[currentPathnameArr.length - 2];
  const lastSlug3 = currentPathnameArr[currentPathnameArr.length - 3];

  if (lastSlug === "readme") {
    return "readme";
  } else if (lastSlug === "week") {
    return "week";
  } else if (
    currentPathnameArr.length === 3 &&
    lastSlug &&
    lastSlug2 &&
    lastSlug3 &&
    isNumeric(lastSlug) &&
    isNumeric(lastSlug2) &&
    isNumeric(lastSlug3)
  ) {
    // date
    return "day";
  } else if (
    currentPathnameArr.length === 2 &&
    lastSlug &&
    lastSlug2 &&
    isNumeric(lastSlug) &&
    isNumeric(lastSlug2)
  ) {
    return "week";
  } else if (currentPathnameArr.length === 0) {
    return "home";
  } else if (
    currentPathnameArr.length === 1 &&
    currentPathnameArr[0] === "week"
  ) {
    return "homeWeek";
  } else {
    return "day";
  }
};

export const getDateString = (isoString, type) => {
  const date = new Date(isoString);
  if (type === "week" || type === "homeWeek") {
    if (isSameWeek(new Date(), date)) {
      return "This week";
    }

    const [year] = getWeekNumber(date);
    const weekStart = date;
    const weekEnd = date.getTime() + 6 * 24 * 60 * 60 * 1000;

    return `${format(weekStart, "MMM do")} - ${format(
      weekEnd,
      "MMM do"
    )}, ${year}`;
  } else {
    if (isToday(date)) {
      return "Today";
    }
    if (isYesterday(date)) {
      return "Yesterday";
    }
    const year = date.getUTCFullYear();
    const nowYear = new Date().getUTCFullYear();
    if (year === nowYear) {
      return format(date, "MMM do");
    } else {
      return format(date, "MMM do, yyyy");
    }
  }
};
export const getManualDateString = (isoString, type) => {
  const date = new Date(isoString);
  if (type === "week" || type === "homeWeek") {
    const year = date.getUTCFullYear();
    const weekStart = date;
    const weekEnd = date.getTime() + 6 * 24 * 60 * 60 * 1000;

    return `${format(weekStart, "MMM do")} - ${format(
      weekEnd,
      "MMM do"
    )}, ${year}`;
  } else {
    return format(date, "MMM do, yyyy");
  }
};
