export const getNameById = (id, type) => {
  const idArr = id.split("-");
  if (type === "week" || type === "homeWeek") {
    return `Week ${idArr[1]}, ${idArr[0]}`;
  } else {
    const date = new Date(id);
    if (isToday(date)) {
      return "Today";
    }
    if (isYesterday(date)) {
      return "Yesterday";
    }
    const year = date.getUTCFullYear();
    const nowYear = new Date().getUTCFullYear();
    if (year === nowYear) {
      return format(date, "MMM do");
    } else {
      return format(date, "MMM do, yyyy");
    }
  }
};
export const getSlugByDay = (someDate) => {
  const date = someDate
    .split("-")
    .filter((item) => item)
    .join("/");

  return `/${date}/`;
};
export const getTitleByRepo = (repo, count, time, index) => {
  let name = repo.split("/")[1];

  let awesomeRemoveCount = 0;
  const nameArr = name.split("-");
  const titleArr = nameArr.filter((titleItem) => {
    if (titleItem.toLowerCase() === "awesome") {
      if (awesomeRemoveCount > 0 || nameArr.length === 1) {
        return true;
      } else {
        awesomeRemoveCount++;
        return false;
      }
    } else {
      return true;
    }
  });
  let tag = "";
  if (time && process.env.GATSBY_BUILD_TIME) {
    const timeStr = getDistance(time, new Date(process.env.GATSBY_BUILD_TIME));
    tag = timeStr;
  }
  const starCount = formatNumber(count);
  return [
    (index !== undefined ? index + 1 + ". " : "") +
      titleCase(titleArr.join(" ")),
    starCount,
    tag,
  ];
};
export const formatNumber = (number) => {
  return millify(number, {
    lowercase: true,
    precision: 1,
  }); // 2.5K
};
export const getDistance = (date, toDate) => {
  const result = formatDistanceStrict(date, toDate, {
    addSuffix: true,
  });
  return result;
  return result
    .replace(" minutes", "m")
    .replace(" minute", "m")
    .replace(" years", "y")
    .replace(" year", "y")
    .replace(" days", "d")
    .replace(" day", "d")

    .replace(" hours", "h")
    .replace(" hour", "h")
    .replace(" seconds", "s")
    .replace(" second", "h");
};
export const getWeekNumber = (d) => {
  // Copy date so don't modify original
  d = new Date(d.getTime());
  // Set to nearest Thursday: current date + 4 - current day number
  // Make Sunday's day number 7
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  // Get first day of year
  var yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  // Calculate full weeks to nearest Thursday
  var weekNo = Math.ceil(((d - yearStart) / 86400000 + 1) / 7);
  // Return array of year and week number
  return [d.getUTCFullYear(), weekNo];
};
export const getInfoById = (id, name) => {
  const idArr = id.split("-");
  let type;
  if (idArr.length === 3) {
    type = "date";
    return {
      type,
      id: id,
      name: name || getNameById(id, type),
      url: getSlugByDay(id),
    };
  } else if (idArr.length === 2) {
    type = "week";

    return {
      type,
      id: id,
      name: name || getNameById(id, type),
      url: getSlugByDay(id),
    };
  } else {
    return {
      type: "unknown",
      id: id,
      name: name || "Unknown",
      url: `/${id}`,
    };
  }
};
