import * as React from "react";
import { Box, Label, Text, Input, Button, Link } from "theme-ui";
import { DEMO_EMAIL_URL } from "../config";
import addToMailchimp from "gatsby-plugin-mailchimp";

const Subscribe = ({ theme = "single", onClose, size = "xl" } = {}) => {
  const [email, setEmail] = React.useState("");
  const [result, setResult] = React.useState("");
  const handleChange = (event) => {
    setEmail(event.target.value);
  };
  const handleSubmit = async (e) => {
    e.preventDefault();
    setEmail("");
    const emailResult = await addToMailchimp(email);
    setResult(emailResult.msg);
    if (emailResult.result === "success") {
      setTimeout(() => {
        onClose && onClose();
      }, 3000);
    }

    // I recommend setting `result` to React state
    // but you can do whatever you want
  };
  return (
    <Box
      as="form"
      name="subscribeForm"
      method="POST"
      sx={{ width: ["auto", size] }}
      onSubmit={handleSubmit}
    >
      <Box
        pb="default"
        sx={{
          fontSize: 1,
          color: theme === "footer" ? "greyDarkLight" : "textMuted",
        }}
      >
        Subscribe to our weekly newsletter to receive the awesome updates! We
        never send spam and you can unsubscribe instantly with one click.&nbsp;
        <Link
          href={DEMO_EMAIL_URL}
          variant="external"
          target="_blank"
          rel="noopener noreferrer"
          sx={{ color: theme === "footer" ? "greyDarkLight" : "textMuted" }}
        >
          Here's past issues.
        </Link>
      </Box>
      <Box>
        <Input
          type="email"
          name="email"
          value={email}
          placeholder="Enter Email Address..."
          onChange={handleChange}
        />
      </Box>
      <Box
        py="2"
        dangerouslySetInnerHTML={{
          __html: result,
        }}
      ></Box>
      <Button
        sx={{
          bg: theme === "footer" ? "primary" : "primary",
          width: "full",
          cursor: "pointer",
        }}
        type="submit"
      >
        Subscribe
      </Button>
    </Box>
  );
};
export default Subscribe;
