import * as React from "react";
import { Box } from "theme-ui";
import { navigate } from "gatsby";
import { getPageType } from "../utils";
import { ReactSearchAutocomplete } from "react-search-autocomplete";

export default function ({ items, location }) {
  const pageType = getPageType(location.pathname);
  const [inputSearchString, setInputSearchString] = React.useState("");
  const handleOnSelect = (item) => {
    setInputSearchString("");
    // the item selected
    navigate(
      pageType === "week" || pageType === "homeWeek"
        ? item.slug + "/week"
        : pageType === "readme"
        ? item.slug + "/readme"
        : item.slug
    );
    // 跳轉
  };
  const handleOnSearch = (string, results) => {
    // onSearch will have as the first callback parameter
    // the string searched and for the second the results.
    setInputSearchString(string);
  };
  return (
    <Box
      sx={{
        position: "relative",
        width: "full",
        mb: "default",
      }}
    >
      <ReactSearchAutocomplete
        items={items}
        fuseOptions={{
          keys: ["repo", "name", "category", "description"],
        }}
        onSearch={handleOnSearch}
        placeholder="Search awesome list"
        inputSearchString={inputSearchString}
        onSelect={handleOnSelect}
        styling={{
          border: 0,
          height: "40px",
          hoverBackgroundColor: "white",
        }}
      />
    </Box>
  );
}
