import * as React from "react";
import {
  Box,
  NavLink,
  Button,
  Heading,
  Flex,
  Link,
  BaseStyles,
  Text,
} from "theme-ui";
import { Link as GatsbyLink } from "gatsby";
import { Left, Right } from "./Icons";
export default function ({ previous, next }) {
  const previousInfo = previous;
  const nextInfo = next;
  return (
    <Box py="md" sx={{ maxWidth: "5xl" }}>
      <Flex sx={{ justifyContent: "space-between", flexWrap: "wrap" }}>
        <Box>
          {previousInfo && (
            <NavLink as={GatsbyLink} variant="navLink" to={previousInfo.url}>
              <Box>
                <Box role="label">Previous</Box>
                <Left size={24}></Left>
                <Text>{previousInfo.name}</Text>
              </Box>
            </NavLink>
          )}
        </Box>
        <Box>
          {nextInfo && (
            <NavLink as={GatsbyLink} variant="navLink" to={nextInfo.url}>
              <Box>
                <Box
                  role="label"
                  sx={{
                    fontSize: 1,
                    textAlign: "right",
                  }}
                >
                  Next
                </Box>

                <Text>{nextInfo.name}</Text>
                <Right size={24}></Right>
              </Box>
            </NavLink>
          )}
        </Box>
      </Flex>
    </Box>
  );
}
