import React from "react";
import { keyframes } from "@emotion/react";
import { Box, Flex, Link, MenuButton, Close, Heading } from "theme-ui";
import { MobileNav } from "../Sidebar";
import { useDisclosure } from "react-use-disclosure";
import { StaticImage } from "gatsby-plugin-image";
import { Logo } from "../Icons";

const fadeIn = keyframes`
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
`;
export default function WithSubnavigation({
  items,
  searchItems,
  location,
  title,
}) {
  const { isOpen, toggle } = useDisclosure();
  return (
    <Box
      sx={{
        position: isOpen ? "sticky" : "sticky",
        top: 0,
        zIndex: 3,
        bg: "background",
      }}
    >
      <Flex
        py="sm"
        px="default"
        sx={{
          minHeight: 60,
          borderBottom: 1,
          borderBottomStyle: "solid",
          borderBottomColor: "background",
          alignItems: "center",
        }}
      >
        <Flex>
          <Link sx={{ position: "relative" }} variant="none" href="/">
            <Box
              sx={{
                display: "inline-block",
                position: "relative",
                top: "6px",
                mr: 1,
              }}
            >
              <Logo size={32}></Logo>
            </Box>

            <Heading
              sx={{ display: "inline-block", lineHeight: "32px" }}
              as="h2"
            >
              {title}
            </Heading>
            <Heading
              as="h5"
              mt="1"
              sx={{
                fontFamily: "monospace",
                fontWeight: 400,
                // letterSpacing: 2,
                color: "gray",
              }}
            >
              // Track it, not just star it.
            </Heading>
          </Link>
        </Flex>

        <Flex
          sx={{
            flex: "1",
            justifyContent: "flex-end",
            flexDirection: "row",
          }}
        >
          <Flex
            sx={{
              display: ["flex", "none"],
              flex: [1, "auto"],
              justifyContent: "flex-end",
            }}
          >
            {isOpen ? (
              <Close onClick={toggle} aria-label={"Toggle Navigation"} />
            ) : (
              <MenuButton onClick={toggle} aria-label={"Toggle Navigation"} />
            )}
          </Flex>
        </Flex>
      </Flex>

      <Box
        pt="default"
        pb="default"
        px="default"
        sx={{
          display: isOpen ? "flex" : "none",
          animation: `${fadeIn} 0.5s`,
          overflowY: "auto",
          height: "calc(100vh - 82px)",
          overscrollBehavior: "contain",
          maxHeight: "100vh",
        }}
      >
        <MobileNav
          searchItems={searchItems}
          location={location}
          items={items}
        />
      </Box>
    </Box>
  );
}
